4690	\begin{lemma}
4691	[Scalar compatibility of the tile comparison at an arbitrary open]
4692	  \label{lem:tile_scalar_compat_genV}
4693	  \lean{AlgebraicGeometry.tile_scalar_compat'}
4694	  \uses{lem:modulesSpecToSheaf_smul_eq, lem:modulesRestrictBasicOpen_smul_eq_genV,
4695	    lem:tile_section_ring_identity_genV}
4696	  The general-open companion of Lemma~\ref{lem:tile_scalar_compat}. Let \(\mathcal{F}\) be a
4697	  quasi-coherent \(\mathcal{O}_{\Spec R}\)-module, let \(g, r \in R\), let \(V \subseteq \Spec R_g\) be
4698	  an \emph{arbitrary} open, and let \(x\) be a section of the affine tile \(\mathcal{F}_{(g)}\) over
4699	  \(V\) --- equivalently, on the underlying carrier, a section of \(\mathcal{F}\) over the
4700	  iterated-image open \(\iota(V)\). Then the native \(R\)-action of \(r\) on \(x\) coincides with the
4701	  \(R_g\)-action of the localised scalar \(\lambda(r) \in R_g\) on \(x\):
4702	  \[
4703	    r \cdot x \;=\; \lambda(r) \cdot x,
4704	    \qquad \lambda : R \to R_g \text{ the localisation map}.
4705	  \]
4706	  The instance at \(V = D(\bar f)\) is the scalar-tower compatibility \(R \to R_g\) at the \emph{target}
4707	  open of the per-tile section localization (Lemma~\ref{lem:tile_section_localization}); the
4708	  \(V = \top\) case is Lemma~\ref{lem:tile_scalar_compat}.
4709	\end{lemma}
4710	\begin{proof}
4711	  \uses{lem:modulesSpecToSheaf_smul_eq, lem:modulesRestrictBasicOpen_smul_eq_genV,
4712	    lem:tile_section_ring_identity_genV}
4713	  The same argument as Lemma~\ref{lem:tile_scalar_compat}, now at an arbitrary open \(V\). By
4714	  Lemma~\ref{lem:modulesSpecToSheaf_smul_eq} the native \(R\)-action of \(r\) on \(x\) reduces to a
4715	  structure-sheaf scalar action, and by Lemma~\ref{lem:modulesRestrictBasicOpen_smul_eq_genV} the
4716	  \(R_g\)-action of \(\lambda(r)\) on \(x\) (as a tile section over \(V\)) reduces to a structure-sheaf
4717	  scalar action on the same underlying carrier. The two scalars then agree by the morphism-level ring
4718	  identity of Lemma~\ref{lem:tile_section_ring_identity_genV} evaluated at \(r\).
4719	\end{proof}
